html:
{% set student_name = frappe.db.get_value('Student', doc.student, 'full_name') or doc.student %}
{% set guardian_name = frappe.db.get_value('Guardian', doc.primary_guardian, 'full_name') if doc.primary_guardian else '' %}
<!DOCTYPE html>
<html>
<head>
<meta charset="utf-8">
<style>
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body { font-family: 'Arial', sans-serif; font-size: 11px; color: #222; background: #fff; }
  .pf { padding: 28px 32px; max-width: 780px; margin: 0 auto; }
  .header { text-align: center; border-bottom: 3px double #333; padding-bottom: 14px; margin-bottom: 18px; }
  .header .logo-placeholder { width: 70px; height: 70px; border: 1px dashed #bbb; margin: 0 auto 8px; display: flex; align-items: center; justify-content: center; font-size: 9px; color: #aaa; }
  .header h1 { font-size: 20px; letter-spacing: 3px; text-transform: uppercase; font-weight: bold; }
  .header h2 { font-size: 12px; color: #555; margin-top: 4px; font-weight: normal; }
  .info-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 0; border: 1px solid #ccc; margin-bottom: 18px; }
  .info-cell { padding: 6px 10px; border-right: 1px solid #ccc; border-bottom: 1px solid #ccc; }
  .info-cell:nth-child(2n) { border-right: none; }
  .info-cell:nth-last-child(-n+2) { border-bottom: none; }
  .info-label { font-size: 9px; text-transform: uppercase; color: #777; letter-spacing: 0.5px; margin-bottom: 2px; }
  .info-value { font-size: 12px; font-weight: bold; }
  table.subjects { width: 100%; border-collapse: collapse; margin-bottom: 18px; }
  table.subjects th { background: #2c3e50; color: #fff; padding: 7px 10px; text-align: left; font-size: 10px; text-transform: uppercase; letter-spacing: 0.5px; }
  table.subjects th.center { text-align: center; }
  table.subjects td { padding: 6px 10px; border-bottom: 1px solid #eee; }
  table.subjects td.center { text-align: center; }
  table.subjects tr:nth-child(even) td { background: #f8f9fa; }
  .apr { color: #1a7a2e; font-weight: bold; }
  .rep { color: #c0392b; font-weight: bold; }
  .summary-row { display: grid; grid-template-columns: 1fr 1fr 1fr 1fr; gap: 10px; margin-bottom: 18px; }
  .summary-card { border: 1px solid #ddd; border-radius: 4px; padding: 10px 8px; text-align: center; }
  .summary-card .sv { font-size: 22px; font-weight: bold; line-height: 1; }
  .summary-card .sl { font-size: 9px; text-transform: uppercase; color: #666; margin-top: 4px; }
  .decision-band { text-align: center; border: 2px solid; border-radius: 4px; padding: 10px; margin-bottom: 18px; }
  .decision-band .dv { font-size: 18px; font-weight: bold; }
  .decision-band.promovido { border-color: #1a7a2e; color: #1a7a2e; }
  .decision-band.retido { border-color: #c0392b; color: #c0392b; }
  .decision-band.concluido { border-color: #2980b9; color: #2980b9; }
  .decision-band.nd { border-color: #999; color: #999; }
  .comments { margin-bottom: 18px; }
  .comment-block { margin-bottom: 10px; }
  .comment-label { font-size: 9px; text-transform: uppercase; color: #777; font-weight: bold; margin-bottom: 4px; }
  .comment-text { border: 1px solid #ddd; padding: 8px 10px; min-height: 50px; border-radius: 2px; font-size: 11px; white-space: pre-wrap; }
  .signatures { display: grid; grid-template-columns: 1fr 1fr 1fr; gap: 30px; margin-top: 36px; }
  .sig { text-align: center; }
  .sig-line { border-top: 1px solid #333; padding-top: 5px; font-size: 10px; color: #555; }
  @media print { .pf { padding: 15px; } }
</style>
</head>
<body>
<div class="pf">
  <div class="header">
    <div class="logo-placeholder">LOGÓTIPO</div>
    <h1>Boletim Escolar</h1>
    <h2>Ano Lectivo: {{ doc.academic_year }}</h2>
  </div>

  <div class="info-grid">
    <div class="info-cell">
      <div class="info-label">Aluno</div>
      <div class="info-value">{{ student_name }}</div>
    </div>
    <div class="info-cell">
      <div class="info-label">Turma</div>
      <div class="info-value">{{ doc.class_group }}</div>
    </div>
    <div class="info-cell">
      <div class="info-label">Classe</div>
      <div class="info-value">{{ doc.school_class }}</div>
    </div>
    <div class="info-cell">
      <div class="info-label">Encarregado de Educação</div>
      <div class="info-value">{{ guardian_name or '—' }}</div>
    </div>
  </div>

  <table class="subjects">
    <thead>
      <tr>
        <th>Disciplina</th>
        <th class="center" style="width:100px">Nota Final</th>
        <th class="center" style="width:110px">Resultado</th>
        <th>Observação</th>
      </tr>
    </thead>
    <tbody>
      {% for row in doc.report_card_rows %}
      <tr>
        <td>{{ row.subject }}</td>
        <td class="center"><strong>{{ '%.1f'|format(row.final_grade) }}</strong></td>
        <td class="center {{ 'apr' if row.result == 'Aprovado' else 'rep' }}">{{ row.result }}</td>
        <td>{{ row.remarks or '' }}</td>
      </tr>
      {% endfor %}
    </tbody>
  </table>

  <div class="summary-row">
    <div class="summary-card">
      <div class="sv">{{ doc.total_subjects }}</div>
      <div class="sl">Total</div>
    </div>
    <div class="summary-card">
      <div class="sv" style="color:#1a7a2e">{{ doc.passed_subjects }}</div>
      <div class="sl">Aprovadas</div>
    </div>
    <div class="summary-card">
      <div class="sv" style="color:#c0392b">{{ doc.failed_subjects }}</div>
      <div class="sl">Reprovadas</div>
    </div>
    <div class="summary-card">
      <div class="sv">{{ '%.1f'|format(doc.overall_average) }}</div>
      <div class="sl">Média Final</div>
    </div>
  </div>

  {% set dc = (doc.final_decision or '')|lower|replace('í','i')|replace('ú','u') %}
  <div class="decision-band {{ dc if dc else 'nd' }}">
    <div style="font-size:10px;text-transform:uppercase;letter-spacing:1px;margin-bottom:4px">Decisão Final</div>
    <div class="dv">{{ doc.final_decision or '—' }}</div>
  </div>

  {% if doc.teacher_comment or doc.management_comment or doc.notes %}
  <div class="comments">
    {% if doc.teacher_comment %}
    <div class="comment-block">
      <div class="comment-label">Comentário do Professor</div>
      <div class="comment-text">{{ doc.teacher_comment }}</div>
    </div>
    {% endif %}
    {% if doc.management_comment %}
    <div class="comment-block">
      <div class="comment-label">Comentário da Direcção</div>
      <div class="comment-text">{{ doc.management_comment }}</div>
    </div>
    {% endif %}
    {% if doc.notes %}
    <div class="comment-block">
      <div class="comment-label">Observações</div>
      <div class="comment-text">{{ doc.notes }}</div>
    </div>
    {% endif %}
  </div>
  {% endif %}

  <div class="signatures">
    <div class="sig"><div class="sig-line">Professor(a) de Turma</div></div>
    <div class="sig"><div class="sig-line">Direcção</div></div>
    <div class="sig"><div class="sig-line">Encarregado de Educação</div></div>
  </div>
</div>
</body>
</html>
